import { Component, inject, OnInit, ChangeDetectorRef } from '@angular/core';
import { FormsModule } from '@angular/forms';

@Component({
  selector: 'app-profile-settings',
  standalone: true,
  imports: [FormsModule],
  templateUrl: './profile-settings.component.html',
  styles: [`
    /* 🕋 Conteneur et carte agrandis (950px) */
    .profile-container { max-width: 950px; margin: 0 auto; padding-top: 10px; }
    .profile-card { background: #ffffff; border-radius: 12px; border: 1px solid #e2e8f0; padding: 40px; box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.05); }
    
    .card-header { margin-bottom: 25px; border-bottom: 1px solid #f1f5f9; padding-bottom: 15px; }
    .card-header h3 { margin: 0 0 6px 0; color: #0f172a; font-size: 20px; font-weight: 700; display: flex; align-items: center; gap: 10px; }
    .card-header p { margin: 0; color: #64748b; font-size: 14px; }
    
    .logo-upload-section { display: flex; align-items: center; gap: 24px; background-color: #f8fafc; padding: 20px; border-radius: 8px; margin-bottom: 25px; }
    .logo-preview { width: 100px; height: 100px; border-radius: 8px; border: 2px solid #e2e8f0; background: #fff; overflow: hidden; display: flex; justify-content: center; align-items: center; }
    .logo-preview img { width: 100%; height: 100%; object-fit: cover; }
    .btn-secondary-upload { background-color: #ffffff; border: 1px solid #cbd5e1; color: #334155; padding: 8px 16px; border-radius: 6px; font-size: 13px; font-weight: 600; cursor: pointer; display: inline-flex; align-items: center; gap: 6px; }
    
    /* 📋 Grille du formulaire adaptée pour 3 colonnes afin d'intégrer l'email sur la ligne 2 */
    .form-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 20px; }
    .form-group { display: flex; flex-direction: column; gap: 6px; }
    .form-group label { font-size: 13px; font-weight: 600; color: #334155; text-align: left; }
    .form-group input, .form-group textarea { width: 100%; padding: 10px 14px; border: 1px solid #cbd5e1; border-radius: 6px; font-size: 14px; box-sizing: border-box; font-family: inherit; }
    
    /* Gestion des étalements de ligne */
    .full-width-row { grid-column: span 3; }
    
    .btn-save { background-color: #0ea5e9; color: white; border: none; border-radius: 6px; padding: 12px 24px; font-size: 14px; font-weight: 600; cursor: pointer; margin-top: 25px; width: 100%; display: inline-flex; align-items: center; justify-content: center; gap: 8px; }
    .alert-box { padding: 12px; border-radius: 6px; margin-bottom: 20px; font-size: 14px; text-align: center; font-weight: 600; }
    .alert-success { background-color: #e6f4ea; color: #137333; border: 1px solid #ceead6; }
  `]
})
export class ProfileSettingsComponent implements OnInit {
  private cdr = inject(ChangeDetectorRef);

  // 🚀 Ajout du champ email
  profile = { company_name: '', phone: '', email: '', address: '', company_bio: '' };
  logoPreviewUrl: string | null = null;
  selectedFile: File | null = null;
  successMessage = '';

  ngOnInit() {
    this.loadCurrentProfile();
  }

  loadCurrentProfile() {
    const targetUrl = 'http://localhost:3000/api/recruiter/profile/details';
    const token = localStorage.getItem('token');

    fetch(targetUrl, {
      method: 'GET',
      headers: { 'Authorization': token ? `Bearer ${token}` : '' }
    })
    .then(async res => {
      if (res.ok) return res.json();
      throw new Error();
    })
    .then(data => {
      if (data) {
        this.profile.company_name = data.company_name || localStorage.getItem('name') || '';
        this.profile.phone = data.phone || '';
        this.profile.email = data.email || ''; // Récupération MySQL
        this.profile.address = data.address || '';
        this.profile.company_bio = data.company_bio || '';
        
        if (data.company_logo) {
          this.logoPreviewUrl = `http://localhost:3000/uploads/${data.company_logo}`;
        }
        this.cdr.detectChanges();
      }
    })
    .catch(() => {
      this.profile.company_name = localStorage.getItem('name') || '';
      this.cdr.detectChanges();
    });
  }

 onFileSelected(event: any) {
  const files = event.target.files;
  if (files && files.length > 0) {
    this.selectedFile = files[0]; // 🚀 Bien prendre le premier index [0] du tableau de fichiers
    const reader = new FileReader();
    reader.onload = () => {
      this.logoPreviewUrl = reader.result as string;
      this.cdr.detectChanges();
    };
    reader.readAsDataURL(this.selectedFile);
  }
}

  onSaveProfile(event: Event) {
    event.preventDefault();

    const targetUrl = 'http://localhost:3000/api/recruiter/profile/update';
    const token = localStorage.getItem('token');

    const formData = new FormData();
formData.append('company_name', this.profile.company_name);
formData.append('phone', this.profile.phone);
formData.append('email', this.profile.email);
formData.append('address', this.profile.address);
formData.append('company_bio', this.profile.company_bio);

// 🚀 CORRECTION CHIRURGICALE : On ne pousse le fichier dans Multer que s'il n'est pas null
if (this.selectedFile) {
  formData.append('logo', this.selectedFile); 
}

    fetch(targetUrl, {
      method: 'POST',
      headers: { 'Authorization': token ? `Bearer ${token}` : '' },
      body: formData
    })
    .then(async res => {
      if (!res.ok) {
        const errorData = await res.json().catch(() => ({}));
        throw new Error(errorData.message || "Impossible de sauvegarder votre profil.");
      }
      return res.json();
    })
    .then(resData => {
      localStorage.setItem('name', this.profile.company_name);
      this.successMessage = resData.message || "Les informations de votre profil et votre logo ont été mis à jour.";
      this.cdr.detectChanges();

      setTimeout(() => {
        this.successMessage = '';
        this.cdr.detectChanges();
      }, 3000);
    })
    .catch(err => alert(err.message));
  }
}
<div class="profile-container">
  <div class="profile-card">
    
    <div class="card-header">
      <h3><i class="bi bi-sliders"></i> Configuration Profil & Logo</h3>
      <p>Modifiez les informations de votre entreprise visibles par les candidats en Tunisie.</p>
    </div>

    @if (successMessage) {
      <div class="alert-box alert-success">
        <i class="bi bi-check-circle-fill"></i> {{ successMessage }}
      </div>
    }

    <form (ngSubmit)="onSaveProfile($event)">
      
      <!-- Section Logo -->
      <div class="logo-upload-section">
        <div class="logo-preview">
          @if (logoPreviewUrl) {
            <img [src]="logoPreviewUrl" alt="Logo Entreprise">
          } @else {
            <i class="bi bi-building-fill" style="font-size: 32px; color: #cbd5e1;"></i>
          }
        </div>
        
        <div class="upload-actions">
          <input type="file" id="logoInput" accept="image/*" (change)="onFileSelected($event)" style="display: none;">
          <button type="button" class="btn-secondary-upload" onclick="document.getElementById('logoInput').click()">
            <i class="bi bi-cloud-upload-fill"></i> Sélectionner un nouveau logo
          </button>
          <p style="margin: 6px 0 0 0; font-size: 12px; color: #64748b; text-align: left;">Formats acceptés : JPG, PNG (Max: 2Mo)</p>
        </div>
      </div>

      <!-- Grille à 3 colonnes optimisée -->
      <div class="form-grid">
        
        <!-- Colonne 1 : Raison Sociale -->
        <div class="form-group">
          <label for="company_name">Raison sociale (Nom) *</label>
          <input type="text" id="company_name" name="company_name" [(ngModel)]="profile.company_name" required placeholder="Ex: TunJob Tech">
        </div>

        <!-- Colonne 2 : Téléphone -->
        <div class="form-group">
          <label for="phone">Téléphone de contact *</label>
          <input type="text" id="phone" name="phone" [(ngModel)]="profile.phone" required placeholder="Ex: +216 71 000 000">
        </div>

        <!-- 🚀 Colonne 3 : NOUVEAU CHAMP EMAIL -->
        <div class="form-group">
          <label for="email">Email de contact *</label>
          <input type="email" id="email" name="email" [(ngModel)]="profile.email" required placeholder="Ex: contact@entreprise.tn">
        </div>

        <!-- Ligne complète : Adresse -->
        <div class="form-group full-width-row">
          <label for="address">Adresse du siège social *</label>
          <input type="text" id="address" name="address" [(ngModel)]="profile.address" required placeholder="Ex: Les Berges du Lac 2, Tunis, Tunisie">
        </div>

        <!-- Ligne complète : Présentation -->
        <div class="form-group full-width-row">
          <label for="company_bio">Présentation de l'entreprise & Activités *</label>
          <textarea id="company_bio" name="company_bio" [(ngModel)]="profile.company_bio" rows="5" required placeholder="Décrivez votre histoire, vos technologies majeures et vos ambitions sur le marché tunisien..."></textarea>
        </div>
      </div>

      <button type="submit" class="btn-save">
        <i class="bi bi-shield-check"></i> Enregistrer les modifications
      </button>

    </form>
  </div>
</div>
